namespace BgControls.Windows.Controls.DragDrop;public class LinearDropVisualProvider : IDropVisualProvider{    public virtual FrameworkElement CreateDropVisual()    {        return new LinearDropVisual();    }    private static Point GetLocationFromScrollViewer(FrameworkElement container, ScrollViewer scrollViewer, Panel panel, ItemDropPosition dropPosition)    {        if (scrollViewer != null)        {            Point point = container.TransformToVisual(scrollViewer).Transform(default(Point));            if (dropPosition == ItemDropPosition.After)            {                if (panel.GetPanelOrientation() == Orientation.Vertical)                {                    return new Point(0.0, point.Y + container.ActualHeight);                }                return new Point(point.X + container.ActualWidth, 0.0);            }            if (panel.GetPanelOrientation() == Orientation.Vertical)            {                return new Point(0.0, point.Y);            }            return new Point(point.X, 0.0);        }        return default(Point);    }    public virtual Point GetLocation(RadListBoxItem container, Panel panel, ItemDropPosition dropPosition)    {        if (container != null)        {            ScrollViewer scrollViewer = panel.ParentOfType<ScrollViewer>();            if (scrollViewer != null && !scrollViewer.CanContentScroll)            {                return GetLocationFromScrollViewer(container, scrollViewer, panel, dropPosition);            }            Point point = container.TransformToVisual(panel).Transform(default(Point));            if (dropPosition == ItemDropPosition.After)            {                if (panel.GetPanelOrientation() == Orientation.Vertical)                {                    return new Point(0.0, point.Y + container.ActualHeight);                }                return new Point(point.X + container.ActualWidth, 0.0);            }        }        return GetLocation(container, panel);    }    public virtual Point GetLocation(RadListBoxItem container, Panel panel)    {        if (container != null)        {            Point point = container.TransformToVisual(panel).Transform(default(Point));            if (panel.GetPanelOrientation() == Orientation.Vertical)            {                return new Point(0.0, point.Y);            }            return new Point(point.X, 0.0);        }        return default(Point);    }    public virtual Thickness GetDropCueHighlightMargin(RadListBoxItem container, Panel panel, FrameworkElement dropVisual)    {        return default(Thickness);    }    public virtual void VisualizeDropPlaceholderStarted(RadListBoxItem container, Panel panel, object dataItem, FrameworkElement dropVisual)    {        // StyleManager.SetThemeFromParent(dropVisual, container);    }    public virtual void VisualizeDropPlaceholderEnded(RadListBoxItem container, Panel panel, object dataItem, FrameworkElement dropVisual)    {        Orientation panelOrientation = panel.GetPanelOrientation();        if (dropVisual is LinearDropVisual)        {            ((LinearDropVisual)dropVisual).UpdateOrientationState(panelOrientation);        }        ScrollViewer parent = panel.GetParent<ScrollViewer>();        if (parent != null)        {            if (panelOrientation == Orientation.Vertical && parent.ComputedVerticalScrollBarVisibility == Visibility.Visible)            {                dropVisual.SetValue(FrameworkElement.MarginProperty, new Thickness(2.0, 0.0, 17.0, 0.0));                return;            }            if (panelOrientation == Orientation.Horizontal && parent.ComputedHorizontalScrollBarVisibility == Visibility.Visible)            {                dropVisual.SetValue(FrameworkElement.MarginProperty, new Thickness(0.0, 2.0, 0.0, 17.0));                return;            }        }        dropVisual.SetValue(FrameworkElement.MarginProperty, new Thickness(2.0, 0.0, 2.0, 0.0));    }    internal static Point GetLocationForTheLastItem(RadListBox listbox, Panel panel)    {        if (listbox != null)        {            object item = listbox.Items.OfType<object>().LastOrDefault();            if (listbox.ContainerFromItemOrContainer(item) is FrameworkElement frameworkElement)            {                Point point = frameworkElement.TransformToVisual(panel).Transform(default(Point));                if (panel.GetPanelOrientation() == Orientation.Vertical)                {                    return new Point(0.0, point.Y + frameworkElement.DesiredSize.Height);                }                return new Point(point.X + frameworkElement.DesiredSize.Width, 0.0);            }        }        return default(Point);    }}